const { test } = require('node:test');
const assert = require('node:assert');
const http = require('node:http');
const { app } = require('../server');

function startServer() {
  return new Promise((resolve) => {
    const server = http.createServer(app);
    server.listen(0, () => resolve(server));
  });
}

function get(server, path) {
  return new Promise((resolve, reject) => {
    const { port } = server.address();
    http
      .get(`http://127.0.0.1:${port}${path}`, (res) => {
        let body = '';
        res.on('data', (chunk) => (body += chunk));
        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body) }));
      })
      .on('error', reject);
  });
}

function post(server, path, payload) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify(payload);
    const { port } = server.address();
    const request = http.request(
      {
        hostname: '127.0.0.1',
        port,
        path,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
        },
      },
      (res) => {
        let responseBody = '';
        res.on('data', (chunk) => (responseBody += chunk));
        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(responseBody) }));
      },
    );
    request.on('error', reject);
    request.end(body);
  });
}

test('GET /health returns ok', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/health');
    assert.strictEqual(status, 200);
    assert.deepStrictEqual(body, { status: 'ok' });
  } finally {
    server.close();
  }
});

test('GET /items returns list', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items');
    assert.strictEqual(status, 200);
    assert.ok(Array.isArray(body.items));
    assert.ok(body.items.length >= 2);
  } finally {
    server.close();
  }
});

test('GET /items/:id returns 404 for missing', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items/99999');
    assert.strictEqual(status, 404);
    assert.strictEqual(body.error, 'not_found');
  } finally {
    server.close();
  }
});

test('POST /items/import rejects an invalid middle item without changes', async () => {
  const server = await startServer();
  try {
    const before = await get(server, '/items');
    const response = await post(server, '/items/import', {
      items: [
        { name: 'gamma', qty: 2 },
        { name: ' ', qty: 4 },
        { name: 'delta', qty: 6 },
      ],
    });
    const after = await get(server, '/items');

    assert.strictEqual(response.status, 400);
    assert.deepStrictEqual(response.body, { error: 'invalid_batch', index: 1, field: 'name' });
    assert.deepStrictEqual(after.body.items, before.body.items);
  } finally {
    server.close();
  }
});

test('POST /items/import appends a valid batch with fresh ids', async () => {
  const server = await startServer();
  try {
    const before = await get(server, '/items');
    const batch = [
      { name: 'gamma', qty: 2 },
      { name: 'delta', qty: 6 },
    ];
    const response = await post(server, '/items/import', { items: batch });
    const after = await get(server, '/items');
    const inserted = after.body.items.slice(before.body.items.length);
    const existingIds = new Set(before.body.items.map((item) => item.id));

    assert.strictEqual(response.status, 201);
    assert.deepStrictEqual(response.body, { inserted: batch.length });
    assert.strictEqual(after.body.items.length, before.body.items.length + batch.length);
    assert.deepStrictEqual(
      inserted.map(({ name, qty }) => ({ name, qty })),
      batch,
    );
    assert.ok(inserted.every((item) => Number.isInteger(item.id) && !existingIds.has(item.id)));
    assert.strictEqual(new Set(inserted.map((item) => item.id)).size, batch.length);
  } finally {
    server.close();
  }
});

